        async function uploadMySignature(){
            var fileInput = document.getElementById('mySignatureFile');
            var file = fileInput && fileInput.files[0];
            if(!file){ showToast('warning', t('chooseImageFirst'), ''); return; }
            try{
                var ext = file.name.split('.').pop();
                var path = currentUser.id + '/' + Date.now() + '.' + ext;
                var up = await supabaseClient.storage.from('signatures').upload(path, file);
                if(up.error) throw up.error;
                var pub = supabaseClient.storage.from('signatures').getPublicUrl(path);
                var publicUrl = pub.data.publicUrl;
                var upd = await supabaseClient.from('profiles').update({ signature_url: publicUrl }).eq('id', currentUser.id);
                if(upd.error) throw upd.error;
                currentUser.signature_url = publicUrl;
                if(profilesCache[currentUser.id]) profilesCache[currentUser.id].signature_url = publicUrl;
                showToast('success', t('signatureSaved'), '');
                renderMySignaturePreview();
            }catch(e){
                console.error('uploadMySignature', e);
                showToast('error', t('uploadFailed'), String((e&&e.message)||e));
            }
        }
