        function updateNotifBadge() { const unread = notificationsCache.filter(n => !n.is_read).length; const badge = document.getElementById('notifBadge'); if (unread > 0) { badge.textContent = unread > 99 ? '99+' : unread; badge.classList.remove('app-hidden'); } else { badge.classList.add('app-hidden'); } }
        function renderNotifications() { const list = document.getElementById('notifList'); if (!list) return; if (notificationsCache.length === 0) { list.innerHTML = '<div class="notif-empty"><i class="fas fa-bell-slash" style="font-size:28px;display:block;margin-bottom:10px;"></i>لا توجد إشعارات</div>'; return; } const iconMap = { success: 'fa-check-circle', danger: 'fa-times-circle', info: 'fa-info-circle', warning: 'fa-exclamation-circle' }; list.innerHTML = notificationsCache.map(n => `<div class="notif-item ${n.is_read ? '' : 'unread'}" onclick="markAsRead('${n.id}','${n.page||''}')"><div class="notif-icon ${n.type||'info'}"><i class="fas ${iconMap[n.type]||iconMap.info}"></i></div><div><div class="notif-title">${n.title}</div>${n.message ? `<div class="notif-msg">${n.message}</div>` : ''}<div class="notif-time">${formatDateTime(n.created_at)}</div></div></div>`).join(''); }
