        async function markAsRead(id, page) { const notif = notificationsCache.find(n => n.id === id); if (notif && !notif.is_read) { await supabaseClient.from('notifications').update({ is_read: true }).eq('id', id); notif.is_read = true; updateNotifBadge(); renderNotifications(); } if (page) { document.getElementById('notifPanel').classList.add('hidden'); navigateTo(page); } }
