        // ===================== Reports Module =====================
        function formatDateTime(date){ const d = new Date(date); if (isNaN(d.getTime())) return ''; const day = String(d.getDate()).padStart(2,'0'); const month = String(d.getMonth()+1).padStart(2,'0'); const year = d.getFullYear(); let h = d.getHours(); const mi = String(d.getMinutes()).padStart(2,'0'); const ap = h >= 12 ? 'م' : 'ص'; h = h % 12; if (h === 0) h = 12; return `${day}/${month}/${year} - ${String(h).padStart(2,'0')}:${mi} ${ap}`; }
        function formatDate(date, format = 'DD/MM/YYYY') { const d = new Date(date); const day = String(d.getDate()).padStart(2, '0'); const month = String(d.getMonth() + 1).padStart(2, '0'); const year = d.getFullYear(); if (format === 'MM/DD/YYYY') return `${month}/${day}/${year}`; if (format === 'YYYY-MM-DD') return `${year}-${month}-${day}`; return `${day}/${month}/${year}`; }
        function formatCurrency(amount) { const lang = (data.settings && data.settings.language) || 'ar'; const currencySymbols = lang==='en' ? {'SDG': 'SDG', 'SAR': 'SAR', 'USD': '$', 'EUR': '€', 'AED': 'AED', 'EGP': 'EGP'} : {'SDG': 'ج.س', 'SAR': 'ر.س', 'USD': '$', 'EUR': '€', 'AED': 'د.إ', 'EGP': 'ج.م'}; const symbol = currencySymbols[data.settings.currency] || data.settings.currency; return `${parseFloat(amount).toLocaleString()} ${symbol}`; }
        function t(key) { return translations[data.settings.language][key] || key; }
        function translatePage() { document.querySelectorAll('[data-i18n]').forEach(el => { const key = el.getAttribute('data-i18n'); if (translations[data.settings.language][key]) el.textContent = translations[data.settings.language][key]; }); document.querySelectorAll('[data-i18n-placeholder]').forEach(el => { const key = el.getAttribute('data-i18n-placeholder'); if (translations[data.settings.language][key]) el.placeholder = translations[data.settings.language][key]; }); }
        async function logActivity(module, action, itemName) { try { await supabaseClient.from('activity_log').insert({ id: generateId(), timestamp: new Date().toISOString(), module: module, action: action, itemName: itemName, actor: currentUser?.full_name || 'Unknown' }); } catch (e) { console.warn('logActivity:', e); } if (['gm','admin'].includes(currentUser?.role)) await loadActivityLog(); }
