        async function printKitchenBank(id) {
            const b = kitchenData.bank.find(x => String(x.id) === String(id));
            if (!b) return;
            const company = 'شركة الوطنية للطاقة والهندسة المحدودة';
            const now = new Date().toLocaleDateString('ar-SA');
            const logo = AEECO_INVOICE_LOGO;
            const typeAr = { credit: 'إيداع', debit: 'سحب', transfer: 'تحويل', other: 'أخرى' };
            const imgHtml = await _kSignedImg(b.image_path);
            const amount = b.amount ? (parseFloat(b.amount) || 0).toLocaleString() + ' ' + esc(b.currency) : '-';
            const rows = `<tr><th>التاريخ</th><td>${esc(b.date)}</td></tr><tr><th>اسم البنك</th><td>${esc(b.bank_name)}</td></tr><tr><th>النوع</th><td>${typeAr[b.notification_type] || esc(b.notification_type)}</td></tr><tr><th>المبلغ</th><td>${amount}</td></tr><tr><th>المرجع</th><td>${esc(b.reference || '-')}</td></tr><tr><th>الوصف</th><td>${esc(b.description || '-')}</td></tr>`;
            const win = window.open('', '_blank');
            win.document.write(`<!DOCTYPE html><html dir="rtl"><head><meta charset="UTF-8"><title>إشعار بنكي</title><style>${_prPrintCSS()}</style></head><body><div class="head">${logo ? `<img src="${logo}">` : ''}<div class="doc">إشعار بنكي - مطبخ</div></div><table>${rows}</table>${imgHtml}<div class="footer">طُبع من نظام ${esc(company)} — ${now}</div><br><button onclick="window.print()" style="padding:10px 20px;font-size:14px;cursor:pointer">🖨️ طباعة / حفظ PDF</button></body></html>`);
            win.document.close();
        }
