        async function updatePassword(e) {
            if (e) e.preventDefault();
            const p1 = document.getElementById('newPassword1').value;
            const p2 = document.getElementById('newPassword2').value;
            if (!p1 || p1.length < 6) { showAuthError(t('passwordTooShort')); return; }
            if (p1 !== p2) { showAuthError(t('passwordsMismatch')); return; }
            const btn = document.getElementById('newPasswordSubmitBtn');
            btn.disabled = true;
            const { error } = await supabaseClient.auth.updateUser({ password: p1 });
            btn.disabled = false;
            if (error) { showAuthError(error.message); return; }
            showToast('success', t('passwordUpdated'), '');
            try { await supabaseClient.auth.signOut(); } catch (err) {}
            try { history.replaceState(null, '', window.location.pathname); } catch (err) {}
            document.getElementById('newPasswordForm').style.display = 'none';
            showLoginFromReset();
        }
