        function checkBackupReminder() {
            if (!currentUser || (currentUser.role !== 'gm' && currentUser.role !== 'admin')) return;
            try { if (sessionStorage.getItem('aeeco_backup_dismissed') === '1') return; } catch (e) {}
            var el = document.getElementById('backupReminder');
            var txt = document.getElementById('backupReminderText');
            if (!el) return;
            var last = 0;
            try { last = parseInt(localStorage.getItem('aeeco_last_backup') || '0', 10) || 0; } catch (e) {}
            var days = last ? Math.floor((Date.now() - last) / 86400000) : null;
            if (last === 0) {
                if (txt) txt.textContent = t('backupNever');
                el.classList.remove('app-hidden');
            } else if (days >= 7) {
                if (txt) txt.textContent = t('backupOld').replace('{days}', days);
                el.classList.remove('app-hidden');
            } else {
                el.classList.add('app-hidden');
            }
        }
