        function closeModal(modalId) { document.getElementById(modalId).classList.remove('active'); document.body.style.overflow = ''; const form = document.querySelector(`#${modalId} form`); if (form) form.reset(); }
        function confirmStyled(message, opts) {
            opts = opts || {};
            const type = opts.type || 'danger';
            const theme = {
                danger:  { icon: 'fa-trash-can',            bg: 'rgba(239,68,68,0.12)',  fg: '#EF4444', okClass: 'btn-danger',  okLabel: opts.okLabel || 'حذف' },
                warning: { icon: 'fa-triangle-exclamation',  bg: 'rgba(245,158,11,0.14)', fg: '#F59E0B', okClass: 'btn-primary', okLabel: opts.okLabel || 'متابعة' },
                info:    { icon: 'fa-circle-question',       bg: 'rgba(11,110,79,0.10)',  fg: '#0B6E4F', okClass: 'btn-primary', okLabel: opts.okLabel || 'موافق' }
            }[type];
            const iconEl = document.getElementById('confirmDialogIcon');
            iconEl.style.background = theme.bg; iconEl.style.color = theme.fg;
            iconEl.innerHTML = `<i class="fas ${theme.icon}"></i>`;
            iconEl.style.animation = 'none'; void iconEl.offsetWidth; iconEl.style.animation = 'confirmIconPop .35s cubic-bezier(.34,1.56,.64,1)';
            document.getElementById('confirmDialogTitle').textContent = opts.title || (type === 'danger' ? 'تأكيد الحذف' : type === 'warning' ? 'تنبيه' : 'تأكيد');
            document.getElementById('confirmDialogMessage').textContent = message;
            const okBtn = document.getElementById('confirmDialogOkBtn');
            const cancelBtn = document.getElementById('confirmDialogCancelBtn');
            okBtn.className = 'btn ' + theme.okClass; okBtn.textContent = theme.okLabel;
            cancelBtn.textContent = 'إلغاء';
            openModal('confirmDialogModal');
            return new Promise(function(resolve){
                function done(result){ closeModal('confirmDialogModal'); okBtn.onclick = null; cancelBtn.onclick = null; resolve(result); }
                okBtn.onclick = function(){ done(true); };
                cancelBtn.onclick = function(){ done(false); };
            });
        }
